{
  "pattern": {
    "summary": "Unsigned overflow-boundary exclusion combined with an offset unsigned comparison can be folded to a single unsigned comparison.",
    "description": "Given an integer or integer-vector value X and constant C, InstCombine can fold a boolean combination of an equality test against the unique wraparound boundary with an unsigned compare on X shifted by 1 relative to that boundary. The canonical scalar form is: (icmp ne X, MAX) & (icmp ule (add X, 1), Y) -> icmp ult X, Y, where MAX is all-ones for the bitwidth. More generally, for arbitrary constant C, match eq/ne X, C together with an unsigned compare of Y against X - C or its equivalent affine form, and rewrite to the corresponding canonical unsigned compare with the compare boundary shifted by C+1. The motivating example is the C = -1 instance: excluding X == -1 removes the only wraparound case of X+1, so ((X != -1) & ((X+1) <=u Y)) is equivalent to (X <u Y).",
    "generic_forms": [
      {
        "source": "(icmp ne X, C) & (icmp ule (X + (-C + 1 mod 2^n)), Y)",
        "result": "icmp ult (X - C), Y"
      },
      {
        "source": "(icmp ne X, C) & (icmp uge Y, (X + (-C + 1 mod 2^n)))",
        "result": "icmp ugt Y, (X - C)"
      },
      {
        "source": "(icmp eq X, C) | (icmp ule (X + (-C + 1 mod 2^n)), Y)",
        "result": "icmp ult (X - C), Y"
      },
      {
        "source": "(icmp eq X, C) | (icmp uge Y, (X + (-C + 1 mod 2^n)))",
        "result": "icmp ugt Y, (X - C)"
      }
    ],
    "special_case_from_example": {
      "source": "(icmp ne iN X, -1) & (icmp ule (add X, 1), Y)",
      "result": "icmp ult iN X, Y"
    },
    "matching_notes": [
      "Handle both and/or logical shapes: ne+and and eq+or.",
      "Handle both operand orders of the unsigned compare: ule Shifted, Y and uge Y, Shifted.",
      "The shifted value may appear as add X, K where K is the modular constant encoding of (-C + 1).",
      "When C == 0, this includes the legacy zero-boundary form.",
      "Works for scalar integers and integer vectors lane-wise.",
      "If lowered through logical and/or rather than bitwise i1 ops in vectors/scalars, preserve poison semantics with freeze as needed."
    ],
    "preconditions": [
      "Integer or integer vector type.",
      "The add is ordinary modular integer addition; no extra nowrap assumption is required.",
      "The constants must satisfy the affine relation between the equality-boundary C and the add constant K: K == (-C + 1) mod 2^n."
    ],
    "canonicalization_preference": [
      "Prefer an unsigned compare directly on X (or X - C in the generalized form) against Y.",
      "For the concrete all-ones boundary case, canonical result is icmp ult X, Y or equivalently icmp ugt Y, X depending on operand order."
    ]
